select d.*, c.name as categoryName from dish d
left join category c on d.category_id = c.id


        and d.name like concat('%', #{name}, '%')


        and d.category_id = #{categoryId}


        and d.status = #{status}


order by d.create_time desc

select d.*, c.name as categoryName from dish d
left join category c on d.category_id = c.id
where d.id = #{id}
